code = """import pandas as pd
import json

# Correctly access the raw string result
businesses_with_credit_cards_raw_string = locals()['var_function-call-15419889924824161013']['query_db_response']['results'][0]

# Extract the JSON part from the raw string
json_start = businesses_with_credit_cards_raw_string.find('[')
json_end = businesses_with_credit_cards_raw_string.rfind(']') + 1
json_string = businesses_with_credit_cards_raw_string[json_start:json_end]

businesses_with_credit_cards = json.loads(json_string)

df_businesses = pd.DataFrame(businesses_with_credit_cards)

def parse_categories(attributes):
    if isinstance(attributes, dict) and 'Categories' in attributes and attributes['Categories'] is not None:
        return [cat.strip() for cat in attributes['Categories'].split(',')] if attributes['Categories'] else []
    return []

df_businesses['categories'] = df_businesses['attributes'].apply(parse_categories)
df_exploded = df_businesses.explode('categories')

# Filter out empty categories that might result from businesses with no categories
df_exploded = df_exploded[df_exploded['categories'] != '']

if not df_exploded.empty:
    category_counts = df_exploded.groupby('categories').size().reset_index(name='business_count')
    most_common_category_info = category_counts.loc[category_counts['business_count'].idxmax()]
    most_common_category_name = most_common_category_info['categories']

    business_ids_in_most_common_category = df_exploded[df_exploded['categories'] == most_common_category_name]['business_id'].tolist()

    # Convert business_id to business_ref format
    business_refs_for_query = [bid.replace("businessid_", "businessref_") for bid in business_ids_in_most_common_category]
else:
    most_common_category_name = None
    business_refs_for_query = []

print('__RESULT__:')
print(json.dumps({
    'most_common_category_name': most_common_category_name,
    'business_refs_for_query': business_refs_for_query
}))"""

